// ── Types ──────────────────────────────────────────────────────────────

export type Level = 'Easy' | 'Medium' | 'Hard'

export type EnglishQType =
  | 'error-spotting'
  | 'fill-blank'
  | 'sentence-improvement'
  | 'synonyms'
  | 'antonyms'
  | 'idioms-phrases'
  | 'one-word-substitution'
  | 'spelling-correction'
  | 'cloze-test'
  | 'para-jumble'
  | 'sentence-rearrangement'
  | 'active-passive'
  | 'direct-indirect'
  | 'reading-comprehension'

export type EnglishCategory =
  | 'Vocabulary'
  | 'Grammar'
  | 'Comprehension'
  | 'Sentence Structure'
  | 'Word Power'

export interface EnglishQuestion {
  id: number
  qtype: EnglishQType
  question: string
  options: [string, string, string, string]
  answer: string
  explanation: string
  level: Level
  tier: 'tier1' | 'tier2' | 'both'
  examProb: 'Hot' | 'High' | 'Confirmed' | 'Recurring'
  hint?: string
  ruleNote?: string
  passageId?: number
  grammarTopic?: string
  topic?: string
  ruleTag?: string
}

export interface VocabEntry {
  id: number
  word: string
  pos: string
  meaning: string
  examples: string[]
  synonyms: string[]
  antonyms: string[]
  level: Level
  examProb: 'Hot' | 'High' | 'Confirmed' | 'Recurring'
  mnemonic?: string
}

export interface PassageEntry {
  id: number
  title: string
  text: string
  type: 'cloze' | 'comprehension'
  level: Level
  questionIds: number[]
}

export interface GrammarRule {
  id: number
  category: string
  topic: string
  rule: string
  example: string
  correct: string
  incorrect: string
  correctUsage: string
  incorrectUsage: string
  tip: string
  examProb: 'Hot' | 'High' | 'Confirmed' | 'Recurring'
}

export interface EnglishPYQRecord {
  id: number
  year: number
  shift: string
  exam: string
  qtype: EnglishQType
  question: string
  answer: string
}

