// ── Grammar Rules ──────────────────────────────────────────────────────

export const grammarRules: GrammarRule[] = [
  { id: 1, category: 'SVA', topic: 'SVA', rule: 'A singular subject takes a singular verb.', example: 'He goes to school every day.', correct: 'He goes to school every day.', incorrect: 'He go to school every day.', correctUsage: 'He goes to school every day.', incorrectUsage: 'He go to school every day.', tip: 'Match subject number with verb.', examProb: 'Hot' },
  { id: 2, category: 'SVA', topic: 'SVA', rule: 'Two subjects joined by "and" take a plural verb.', example: 'Ram and Shyam are friends.', correct: 'Ram and Shyam are friends.', incorrect: 'Ram and Shyam is friends.', correctUsage: 'Ram and Shyam are friends.', incorrectUsage: 'Ram and Shyam is friends.', tip: '"And" makes the subject plural.', examProb: 'Hot' },
  { id: 3, category: 'SVA', topic: 'SVA', rule: 'Either/or, neither/nor — verb agrees with the nearer subject.', example: 'Neither the boys nor the teacher was present.', correct: 'Neither the boys nor the teacher was present.', incorrect: 'Neither the boys nor the teacher were present.', correctUsage: 'Neither the boys nor the teacher was present.', incorrectUsage: 'Neither the boys nor the teacher were present.', tip: 'Look at the subject AFTER nor/or.', examProb: 'Hot' },
  { id: 4, category: 'Tenses', topic: 'Tenses', rule: 'Simple Present for habitual actions.', example: 'She reads the newspaper every morning.', correct: 'She reads the newspaper every morning.', incorrect: 'She is reading the newspaper every morning.', correctUsage: 'She reads the newspaper every morning.', incorrectUsage: 'She is reading the newspaper every morning.', tip: 'Use "every day/always/usually" as clues for Simple Present.', examProb: 'Hot' },
  { id: 5, category: 'Tenses', topic: 'Tenses', rule: 'Past Perfect for the earlier of two past events.', example: 'The train had left before I reached the station.', correct: 'The train had left before I reached the station.', incorrect: 'The train left before I reached the station.', correctUsage: 'The train had left before I reached the station.', incorrectUsage: 'The train left before I reached the station.', tip: 'Earlier event = had + V3; later event = Simple Past.', examProb: 'Confirmed' },
  { id: 6, category: 'Tenses', topic: 'Tenses', rule: 'Since + point in time; For + duration.', example: 'She has been working here since 2010.', correct: 'She has been working here since 2010.', incorrect: 'She has been working here for 2010.', correctUsage: 'She has been working here since 2010.', incorrectUsage: 'She has been working here for 2010.', tip: '"Since" = specific time; "For" = period/length.', examProb: 'Hot' },
  { id: 7, category: 'Articles', topic: 'Articles', rule: '"An" before vowel sounds, "A" before consonant sounds.', example: 'An honest man; A university student.', correct: 'An honest man; A university student.', incorrect: 'A honest man; An university student.', correctUsage: 'An honest man; A university student.', incorrectUsage: 'A honest man; An university student.', tip: 'Focus on SOUND, not letter. H is silent in honest; U sounds like "yoo" in university.', examProb: 'Hot' },
  { id: 8, category: 'Articles', topic: 'Articles', rule: '"The" for unique or specific nouns.', example: 'The sun rises in the east.', correct: 'The sun rises in the east.', incorrect: 'Sun rises in east.', correctUsage: 'The sun rises in the east.', incorrectUsage: 'Sun rises in east.', tip: 'Unique things (sun, moon, earth) and directions take "the".', examProb: 'Confirmed' },
  { id: 9, category: 'Prepositions', topic: 'Prepositions', rule: '"At" for specific time, "On" for days/dates, "In" for months/years.', example: 'I wake up at 6 am on Monday in January.', correct: 'I wake up at 6 am on Monday in January.', incorrect: 'I wake up in 6 am at Monday on January.', correctUsage: 'I wake up at 6 am on Monday in January.', incorrectUsage: 'I wake up in 6 am at Monday on January.', tip: 'At (point) < On (day) < In (larger period).', examProb: 'Hot' },
  { id: 10, category: 'Prepositions', topic: 'Prepositions', rule: '"Between" for two; "Among" for more than two.', example: 'Divide the sweets between Ram and Shyam.', correct: 'Divide the sweets between Ram and Shyam.', incorrect: 'Divide the sweets among Ram and Shyam.', correctUsage: 'Divide the sweets between Ram and Shyam.', incorrectUsage: 'Divide the sweets among Ram and Shyam.', tip: 'Between = 2; Among = 3+.', examProb: 'Confirmed' },
  { id: 11, category: 'Voice', topic: 'Voice', rule: 'Active to Passive: Object becomes subject, verb becomes be + V3.', example: 'The letter was written by her.', correct: 'The letter was written by her.', incorrect: 'The letter written by her.', correctUsage: 'The letter was written by her.', incorrectUsage: 'The letter written by her.', tip: 'Subject + be + V3 + by + agent.', examProb: 'Hot' },
  { id: 12, category: 'Speech', topic: 'Speech', rule: 'Direct to Indirect: Remove quotes, shift tense back.', example: 'He said that he was tired.', correct: 'He said that he was tired.', incorrect: 'He said that he is tired.', correctUsage: 'He said that he was tired.', incorrectUsage: 'He said that he is tired.', tip: 'Reporting verb in past = shift tenses back one step.', examProb: 'Hot' },
  { id: 13, category: 'Modifiers', topic: 'Modifiers', rule: 'Place modifiers close to the word they modify.', example: 'She spent almost Rs 1000.', correct: 'She spent almost Rs 1000.', incorrect: 'She almost spent Rs 1000.', correctUsage: 'She spent almost Rs 1000.', incorrectUsage: 'She almost spent Rs 1000.', tip: '"Almost" modifies the amount, not the action of spending.', examProb: 'High' },
  { id: 14, category: 'SVA', topic: 'SVA', rule: 'Collective nouns take singular verb when acting as a unit.', example: 'The team is playing well.', correct: 'The team is playing well.', incorrect: 'The team are playing well.', correctUsage: 'The team is playing well.', incorrectUsage: 'The team are playing well.', tip: 'Team/committee/jury = singular when acting together.', examProb: 'Hot' },
  { id: 15, category: 'Tenses', topic: 'Tenses', rule: 'Present Perfect with "just, already, yet, ever, never".', example: 'I have just finished my work.', correct: 'I have just finished my work.', incorrect: 'I just finished my work.', correctUsage: 'I have just finished my work.', incorrectUsage: 'I just finished my work.', tip: 'These adverbs signal Present Perfect.', examProb: 'Confirmed' },
  { id: 16, category: 'Articles', topic: 'Articles', rule: 'No article before uncountable nouns in general sense.', example: 'Water is essential for life.', correct: 'Water is essential for life.', incorrect: 'The water is essential for life.', correctUsage: 'Water is essential for life.', incorrectUsage: 'The water is essential for life.', tip: 'General statements about uncountable nouns need no article.', examProb: 'High' },
  { id: 17, category: 'Prepositions', topic: 'Prepositions', rule: '"Beside" means "next to"; "Besides" means "in addition to".', example: 'He sat beside me. Besides English, he speaks Hindi.', correct: 'He sat beside me. Besides English, he speaks Hindi.', incorrect: 'He sat besides me. Beside English, he speaks Hindi.', correctUsage: 'He sat beside me. Besides English, he speaks Hindi.', incorrectUsage: 'He sat besides me. Beside English, he speaks Hindi.', tip: 'Beside = physical; Besides = additional.', examProb: 'Hot' },
  { id: 18, category: 'Voice', topic: 'Voice', rule: 'Modal verbs in passive: modal + be + V3.', example: 'The work can be done by him.', correct: 'The work can be done by him.', incorrect: 'The work can done by him.', correctUsage: 'The work can be done by him.', incorrectUsage: 'The work can done by him.', tip: 'Always include "be" with modals in passive.', examProb: 'Confirmed' },
  { id: 19, category: 'Speech', topic: 'Speech', rule: 'Questions in indirect speech: asked + if/whether (yes/no) or wh-word.', example: 'She asked if I was coming.', correct: 'She asked if I was coming.', incorrect: 'She asked that was I coming.', correctUsage: 'She asked if I was coming.', incorrectUsage: 'She asked that was I coming.', tip: 'Yes/No questions use "if/whether"; Wh-questions keep the wh-word.', examProb: 'Hot' },
  { id: 20, category: 'Modifiers', topic: 'Modifiers', rule: 'Dangling modifier: the subject must be stated clearly.', example: 'Walking to school, I saw a bird.', correct: 'Walking to school, I saw a bird.', incorrect: 'Walking to school, a bird was seen.', correctUsage: 'Walking to school, I saw a bird.', incorrectUsage: 'Walking to school, a bird was seen.', tip: 'Who is walking? The subject after the comma must match.', examProb: 'High' },
]

